        _mint(to, amount);
    }

    /// @notice Convenience: mint to msg.sender
    function faucet(uint256 amount) external {
        _mint(msg.sender, amount);
    }
}

contracts/SphereAgentWallet.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

/// @title SphereAgentWallet — Budget escrow for AI agent execution
contract SphereAgentWallet {
    using SafeERC20 for IERC20;

    address public owner;
    address public agent;
    bool public isActive;

    mapping(address => uint256) public budgets;    // token => funded amount
    mapping(address => uint256) public spent;      // token => spent amount

    event Funded(address indexed token, uint256 amount);
    event Spent(address indexed token, address indexed to, uint256 amount);
    event Refunded(address indexed token, address indexed to, uint256 amount);
    event AgentSet(address indexed agent);
    event SessionStarted();
    event SessionStopped();

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    modifier onlyAgent() {
        require(msg.sender == agent, "Not agent");
        _;
    }

    modifier onlyActive() {
        require(isActive, "Session not active");
        _;
    }

    constructor(address _owner) {
        owner = _owner;
    }

    /// @notice Set the authorized agent address
    function setAgent(address _agent) external onlyOwner {
        agent = _agent;
        emit AgentSet(_agent);
    }

    /// @notice Fund the agent wallet with a budget
    function fund(address token, uint256 amount) external onlyOwner {
        require(amount > 0, "Zero amount");
        IERC20(token).safeTransferFrom(msg.sender, address(this), amount);
        budgets[token] += amount;
        emit Funded(token, amount);
    }

    /// @notice Start an agent session
    function startSession() external onlyOwner {
        require(agent != address(0), "No agent set");
        isActive = true;
        emit SessionStarted();
    }

    /// @notice Agent spends from budget
    function spend(
        address token,
        uint256 amount,
        address to
    ) external onlyAgent onlyActive {
        uint256 remaining = budgets[token] - spent[token];
        require(amount <= remaining, "Exceeds budget");

        spent[token] += amount;
        IERC20(token).safeTransfer(to, amount);

        emit Spent(token, to, amount);
    }

    /// @notice Stop session and refund unspent budget to owner
    function stopAndRefund() external onlyOwner {
        isActive = false;
        emit SessionStopped();
    }

    /// @notice Refund remaining budget for a specific token
    function refund(address token) external onlyOwner {
        uint256 remaining = budgets[token] - spent[token];
        require(remaining > 0, "Nothing to refund");

        budgets[token] = spent[token]; // Set budget to spent amount
        IERC20(token).safeTransfer(owner, remaining);

        emit Refunded(token, owner, remaining);
    }

    /// @notice Get remaining budget for a token
    function remainingBudget(address token) external view returns (uint256) {
        return budgets[token] - spent[token];
    }

    /// @notice Get total spent for a token
    function totalSpent(address token) external view returns (uint256) {
        return spent[token];
    }
}

contracts/SphereDistributor.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

/// @title SphereDistributor — Batch payroll / multi-send distribution
contract SphereDistributor {
    using SafeERC20 for IERC20;

    event Distribution(
        address indexed sender,
        address indexed token,
        uint256 totalAmount,
        uint256 recipientCount
    );

    event SingleTransfer(
        address indexed sender,
        address indexed token,
        address indexed recipient,
        uint256 amount
    );

    /// @notice Distribute tokens to multiple recipients in a single transaction
    /// @param token The ERC20 token to distribute
    /// @param recipients Array of recipient addresses
    /// @param amounts Array of amounts (must match recipients length)
    function distribute(
        address token,
        address[] calldata recipients,
        uint256[] calldata amounts
    ) external {
        require(recipients.length == amounts.length, "Length mismatch");
        require(recipients.length > 0, "Empty recipients");

        uint256 totalAmount = 0;
        for (uint256 i = 0; i < amounts.length; i++) {
            require(amounts[i] > 0, "Zero amount");
            require(recipients[i] != address(0), "Zero address");
            totalAmount += amounts[i];
        }

        // Pull total from sender in one transfer
        IERC20(token).safeTransferFrom(msg.sender, address(this), totalAmount);

        // Distribute to each recipient
        for (uint256 i = 0; i < recipients.length; i++) {
            IERC20(token).safeTransfer(recipients[i], amounts[i]);
            emit SingleTransfer(msg.sender, token, recipients[i], amounts[i]);
        }

        emit Distribution(msg.sender, token, totalAmount, recipients.length);
    }

    /// @notice Simple single transfer (convenience)
    function transfer(
        address token,
        address recipient,
        uint256 amount
    ) external {
        require(recipient != address(0), "Zero address");
        require(amount > 0, "Zero amount");

        IERC20(token).safeTransferFrom(msg.sender, recipient, amount);
        emit SingleTransfer(msg.sender, token, recipient, amount);
    }
}

contracts/SphereSwapRouter.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

/// @title SphereSwapRouter — Simplified Uniswap V2 constant-product AMM
contract SphereSwapRouter {
    using SafeERC20 for IERC20;

    struct Pool {
        uint256 reserveA;
        uint256 reserveB;
        address tokenA;
        address tokenB;
        bool exists;
    }

    mapping(bytes32 => Pool) public pools;

    event LiquidityAdded(
        address indexed tokenA,
        address indexed tokenB,
        uint256 amountA,
        uint256 amountB
    );

    event Swap(
        address indexed sender,
        address indexed tokenIn,
        address indexed tokenOut,
        uint256 amountIn,
        uint256 amountOut
    );

    /// @notice Get canonical pool key (sorted by address)
    function _poolKey(address tokenA, address tokenB) internal pure returns (bytes32) {
        (address t0, address t1) = tokenA < tokenB ? (tokenA, tokenB) : (tokenB, tokenA);
        return keccak256(abi.encodePacked(t0, t1));
    }

    /// @notice Add liquidity to a pool (creates it if it doesn't exist)
    function addLiquidity(
        address tokenA,
        address tokenB,
        uint256 amountA,
        uint256 amountB
    ) external {
        require(tokenA != tokenB, "Identical tokens");
        require(amountA > 0 && amountB > 0, "Zero amounts");

        bytes32 key = _poolKey(tokenA, tokenB);
        Pool storage pool = pools[key];

        IERC20(tokenA).safeTransferFrom(msg.sender, address(this), amountA);
        IERC20(tokenB).safeTransferFrom(msg.sender, address(this), amountB);

        if (!pool.exists) {
            (address t0, address t1) = tokenA < tokenB ? (tokenA, tokenB) : (tokenB, tokenA);
            (uint256 a0, uint256 a1) = tokenA < tokenB ? (amountA, amountB) : (amountB, amountA);
            pool.tokenA = t0;
            pool.tokenB = t1;
            pool.reserveA = a0;
            pool.reserveB = a1;
            pool.exists = true;
        } else {
            if (tokenA == pool.tokenA) {
                pool.reserveA += amountA;
                pool.reserveB += amountB;
            } else {
                pool.reserveA += amountB;
                pool.reserveB += amountA;
            }
        }

        emit LiquidityAdded(tokenA, tokenB, amountA, amountB);
    }

    /// @notice Get output amount for a swap (constant product: x * y = k)
    function getAmountOut(
        address tokenIn,
        address tokenOut,
        uint256 amountIn
    ) public view returns (uint256 amountOut) {
        bytes32 key = _poolKey(tokenIn, tokenOut);
        Pool storage pool = pools[key];
        require(pool.exists, "Pool does not exist");

        (uint256 reserveIn, uint256 reserveOut) = tokenIn == pool.tokenA
            ? (pool.reserveA, pool.reserveB)
            : (pool.reserveB, pool.reserveA);

        require(reserveIn > 0 && reserveOut > 0, "Insufficient liquidity");

        // 0.3% fee
        uint256 amountInWithFee = amountIn * 997;
        uint256 numerator = amountInWithFee * reserveOut;
        uint256 denominator = (reserveIn * 1000) + amountInWithFee;
        amountOut = numerator / denominator;
    }

    /// @notice Execute a swap
    function swap(
        address tokenIn,
        address tokenOut,
        uint256 amountIn,
        uint256 minAmountOut
    ) external returns (uint256 amountOut) {
        amountOut = getAmountOut(tokenIn, tokenOut, amountIn);
        require(amountOut >= minAmountOut, "Slippage exceeded");

        bytes32 key = _poolKey(tokenIn, tokenOut);
        Pool storage pool = pools[key];

        // Transfer tokenIn from sender
        IERC20(tokenIn).safeTransferFrom(msg.sender, address(this), amountIn);

        // Update reserves
        if (tokenIn == pool.tokenA) {
            pool.reserveA += amountIn;
            pool.reserveB -= amountOut;
        } else {
            pool.reserveB += amountIn;
            pool.reserveA -= amountOut;
        }

        // Transfer tokenOut to sender
        IERC20(tokenOut).safeTransfer(msg.sender, amountOut);

        emit Swap(msg.sender, tokenIn, tokenOut, amountIn, amountOut);
    }

    /// @notice Get pool reserves
    function getReserves(address tokenA, address tokenB)
        external
        view
        returns (uint256 reserveA, uint256 reserveB)
    {
        bytes32 key = _poolKey(tokenA, tokenB);
        Pool storage pool = pools[key];
        require(pool.exists, "Pool does not exist");

        if (tokenA == pool.tokenA) {
            return (pool.reserveA, pool.reserveB);
        } else {
            return (pool.reserveB, pool.reserveA);
        }
    }
}

contracts/SphereYieldVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

/// @title SphereYieldVault — Simple yield vault with mock yield accrual
contract SphereYieldVault {
    using SafeERC20 for IERC20;

    struct Deposit {
        uint256 amount;
        uint256 shares;
        uint256 depositBlock;
        bool active;
    }

    IERC20 public immutable asset;
    uint256 public totalShares;
    uint256 public totalDeposited;

    // Mock yield rate: basis points per block (1 = 0.01% per block)
    uint256 public yieldRateBps = 1;

    mapping(address => Deposit) public deposits;

    event Deposited(address indexed user, uint256 amount, uint256 shares);
    event Withdrawn(address indexed user, uint256 amount, uint256 shares);
    event Harvested(address indexed user, address indexed to, uint256 yield_);

    constructor(address _asset) {
        asset = IERC20(_asset);
    }

    /// @notice Deposit tokens into the vault
    function deposit(uint256 amount) external returns (uint256 shares) {
        require(amount > 0, "Zero amount");

        // If user has existing deposit, harvest first
        if (deposits[msg.sender].active) {
            _harvest(msg.sender, msg.sender);
        }

        asset.safeTransferFrom(msg.sender, address(this), amount);

        // 1:1 share ratio for simplicity
        shares = amount;
        totalShares += shares;
        totalDeposited += amount;

        Deposit storage d = deposits[msg.sender];
        d.amount += amount;
        d.shares += shares;
        d.depositBlock = block.number;
        d.active = true;

        emit Deposited(msg.sender, amount, shares);
    }

    /// @notice Withdraw all deposited tokens + accrued yield
    function withdraw() external returns (uint256 totalReturn) {
        Deposit storage d = deposits[msg.sender];
        require(d.active, "No active deposit");

        uint256 yield_ = _calculateYield(msg.sender);
        totalReturn = d.amount + yield_;

        uint256 shares = d.shares;
        totalShares -= shares;
        totalDeposited -= d.amount;

        d.amount = 0;
        d.shares = 0;
        d.active = false;

        // Mint yield (testnet only — vault mints to cover yield)
        if (yield_ > 0) {
            // In production this would come from actual yield strategies
            // For testnet, we just transfer what we have (yield is simulated)
        }

        asset.safeTransfer(msg.sender, d.amount > 0 ? d.amount : totalReturn);

        emit Withdrawn(msg.sender, totalReturn, shares);
    }

    /// @notice Harvest accrued yield to a specific address
    function harvest(address to) external returns (uint256 yield_) {
        yield_ = _harvest(msg.sender, to);
    }

    /// @notice View accrued yield for a user
    function accruedYield(address user) external view returns (uint256) {
        return _calculateYield(user);
    }

    /// @notice View deposit info
    function getDeposit(address user)
        external
        view
        returns (uint256 amount, uint256 shares, uint256 depositBlock, bool active)
    {
        Deposit storage d = deposits[user];
        return (d.amount, d.shares, d.depositBlock, d.active);
    }

    function _harvest(address user, address to) internal returns (uint256 yield_) {
        Deposit storage d = deposits[user];
        require(d.active, "No active deposit");

        yield_ = _calculateYield(user);
        if (yield_ > 0) {
            d.depositBlock = block.number; // Reset yield calculation
            // Transfer yield (in production, from actual yield; on testnet, from vault balance)
            uint256 vaultBalance = asset.balanceOf(address(this));
            uint256 transferAmount = yield_ > vaultBalance ? vaultBalance : yield_;
            if (transferAmount > 0) {
                asset.safeTransfer(to, transferAmount);
            }
        }

        emit Harvested(user, to, yield_);
    }

    /// @notice Calculate mock yield: amount * yieldRateBps * blocks / 10000
    function _calculateYield(address user) internal view returns (uint256) {
        Deposit storage d = deposits[user];
        if (!d.active || d.amount == 0) return 0;

        uint256 blocksPassed = block.number - d.depositBlock;
        return (d.amount * yieldRateBps * blocksPassed) / 10000;
    }
}

